class Solution:
    def findSolution(self, customfunction: 'CustomFunction', z: int) -> List[List[int]]:
        res = []
        for x in range(1, 1001):
            if customfunction.f(x, 1) > z:
                break
            if customfunction.f(x, 1000) < z:
                continue
            lo, hi = 1, 1000
            while lo <= hi:
                mid = (lo + hi) // 2
                v = customfunction.f(x, mid)
                if v == z:
                    res.append([x, mid])
                    break
                elif v < z:
                    lo = mid + 1
                else:
                    hi = mid - 1
        return res

