var findSolution = function(customfunction, z) {
    const res = [];
    let x = 1, y = 1000;
    while (x <= 1000 && y >= 1) {
        const v = customfunction.f(x, y);
        if (v === z) {
            res.push([x, y]);
            x += 1;
            y -= 1;
        } else if (v < z) {
            x += 1;
        } else {
            y -= 1;
        }
    }
    return res;
};
